content.content:
  1→/* ── Glow tokens (light) — warm sun glow ── */
  2→.explore-page-container{
  3→    --hero-glow-border: rgba(255, 170, 40, 0.35);
  4→    --hero-glow-core: rgba(255, 180, 50, 0.25);
  5→    --hero-glow-tight: rgba(255, 165, 30, 0.2);
  6→    --hero-glow-mid: rgba(255, 145, 20, 0.12);
  7→    --hero-glow-wide: rgba(255, 120, 10, 0.06);
  8→    --hero-glow-ambient: rgba(255, 100, 0, 0.03);
  9→}
 10→
 11→/* ── Glow tokens (dark) — luminous sun/star corona ── */
 12→[data-theme="dark"] .explore-page-container{
 13→    --hero-glow-border: rgba(255, 180, 50, 0.4);
 14→    --hero-glow-core: rgba(255, 190, 60, 0.3);
 15→    --hero-glow-tight: rgba(255, 170, 40, 0.28);
 16→    --hero-glow-mid: rgba(255, 150, 25, 0.16);
 17→    --hero-glow-wide: rgba(255, 130, 15, 0.08);
 18→    --hero-glow-ambient: rgba(255, 110, 5, 0.04);
 19→}
 20→
 21→.explore-page-container{
 22→    width: 100%;
 23→    min-height: 100vh;
 24→    padding-bottom: 4.5rem;
 25→}
 26→
 27→.explore-page-container .search-shell{
 28→    top: 0;
 29→}
 30→
 31→/* ── Section title ── */
 32→.explore-section-title{
 33→    display: flex;
 34→    align-items: center;
 35→    gap: 0.5rem;
 36→    width: 100%;
 37→    padding: 0.75rem 0.85rem 0.5rem 0.85rem;
 38→    box-sizing: border-box;
 39→    font-family: var(--font-ui);
 40→    font-size: 0.68rem;
 41→    font-weight: 700;
 42→    letter-spacing: 0.08rem;
 43→    text-transform: uppercase;
 44→    color: var(--text-faint);
 45→}
 46→.explore-section-title::after{
 47→    content: '';
 48→    flex: 1;
 49→    height: 1px;
 50→    background: var(--border-card);
 51→}
 52→.explore-section-title--runners{
 53→    padding-top: 0.25rem;
 54→}
 55→
 56→
 57→/* ══════════════════════════════════════════
 58→   HERO CARD — #1 Hottest
 59→   ══════════════════════════════════════════ */
 60→
 61→.explore-hero-section{
 62→    padding: 0 8px;
 63→    margin-bottom: 0.25rem;
 64→}
 65→
 66→/* Wrapper: positions the glow behind the card */
 67→.explore-hero-wrap{
 68→    position: relative;
 69→    width: 100%;
 70→}
 71→
 72→.explore-hero-card{
 73→    position: relative;
 74→    display: flex;
 75→    flex-direction: column;
 76→    width: 100%;
 77→    border-radius: 14px;
 78→    overflow: hidden;
 79→    cursor: pointer;
 80→    background: var(--bg-card);
 81→    border: 1.5px solid var(--hero-glow-border);
 82→    box-shadow:
 83→        0 0 8px 2px var(--hero-glow-tight),
 84→        0 0 24px 6px var(--hero-glow-mid),
 85→        0 0 56px 14px var(--hero-glow-wide),
 86→        0 0 100px 28px var(--hero-glow-ambient);
 87→    transition: transform 0.3s ease, box-shadow 0.3s ease;
 88→    z-index: 1;
 89→}
 90→.explore-hero-card:hover{
 91→    transform: translateY(-3px);
 92→    box-shadow:
 93→        0 0 12px 4px var(--hero-glow-tight),
 94→        0 0 32px 10px var(--hero-glow-mid),
 95→        0 0 70px 20px var(--hero-glow-wide),
 96→        0 0 120px 36px var(--hero-glow-ambient);
 97→}
 98→
 99→/* Diffused solar corona glow behind card */
100→.explore-hero-glow{
101→    position: absolute;
102→    inset: -28px;
103→    border-radius: 42px;
104→    z-index: 0;
105→    pointer-events: none;
106→    background:
107→        radial-gradient(
108→            ellipse 90% 70% at 50% 50%,
109→            var(--hero-glow-core) 0%,
110→            var(--hero-glow-mid) 30%,
111→            var(--hero-glow-wide) 55%,
112→            var(--hero-glow-ambient) 75%,
113→            transparent 90%
114→        );
115→    filter: blur(20px);
116→}
117→
118→/* Hero image */
119→.explore-hero-image-wrap{
120→    position: relative;
121→    width: 100%;
122→    max-height: 260px;
123→    overflow: hidden;
124→    z-index: 1;
125→}
126→.explore-hero-image{
127→    width: 100%;
128→    height: 100%;
129→    max-height: 260px;
130→    object-fit: cover;
131→    display: block;
132→}
133→.explore-hero-image-overlay{
134→    position: absolute;
135→    inset: 0;
136→    background: linear-gradient(
137→        to bottom,
138→        transparent 40%,
139→        var(--bg-card) 100%
140→    );
141→    pointer-events: none;
142→}
143→
144→/* Hero body */
145→.explore-hero-body{
146→    position: relative;
147→    z-index: 1;
148→    display: flex;
149→    flex-direction: column;
150→    gap: 0.65rem;
151→    padding: 1.1rem 1.25rem 1rem 1.25rem;
152→}
153→.explore-hero-body--has-image{
154→    margin-top: -2.5rem;
155→}
156→
157→/* Badge pill */
158→.explore-hero-badge{
159→    display: inline-flex;
160→    align-items: center;
161→    gap: 0.3rem;
162→    width: fit-content;
163→    padding: 0.25rem 0.65rem 0.25rem 0.4rem;
164→    border-radius: 20px;
165→    background: linear-gradient(135deg, rgba(212, 168, 83, 0.15), rgba(245, 158, 11, 0.1));
166→    border: 1px solid rgba(212, 168, 83, 0.25);
167→}
168→.explore-hero-flame{
169→    width: 16px;
170→    height: 16px;
171→    color: var(--accent-amber);
172→    animation: flamePulse 2s ease-in-out infinite;
173→}
174→@keyframes flamePulse{
175→    0%, 100%{ transform: scale(1); opacity: 1; }
176→    50%{ transform: scale(1.15); opacity: 0.85; }
177→}
178→.explore-hero-badge-text{
179→    font-family: var(--font-ui);
180→    font-size: 0.65rem;
181→    font-weight: 700;
182→    letter-spacing: 0.04rem;
183→    text-transform: uppercase;
184→    color: var(--accent-amber);
185→}
186→
187→/* Hero title */
188→.explore-hero-title{
189→    margin: 0;
190→    padding: 0;
191→    font-family: "Lexend Deca", sans-serif;
192→    font-size: 1.35rem;
193→    font-weight: 800;
194→    line-height: 1.3;
195→    letter-spacing: -0.03rem;
196→    color: var(--text-heading);
197→}
198→
199→/* Hero excerpt */
200→.explore-hero-excerpt{
201→    margin: 0;
202→    padding: 0;
203→    font-family: var(--font-serif);
204→    font-size: 0.88rem;
205→    font-weight: 400;
206→    line-height: 1.65;
207→    color: var(--text-body);
208→    letter-spacing: 0.005rem;
209→    display: -webkit-box;
210→    -webkit-line-clamp: 3;
211→    -webkit-box-orient: vertical;
212→    overflow: hidden;
213→}
214→
215→/* Hero footer */
216→.explore-hero-footer{
217→    display: flex;
218→    align-items: center;
219→    justify-content: space-between;
220→    flex-wrap: wrap;
221→    gap: 0.5rem;
222→    padding-top: 0.55rem;
223→    border-top: 1px solid var(--border-card);
224→}
225→.explore-hero-author{
226→    display: flex;
227→    align-items: center;
228→    gap: 0.4rem;
229→}
230→.explore-hero-stats{
231→    display: flex;
232→    align-items: center;
233→    gap: 0.35rem;
234→}
235→.explore-hero-score-pill{
236→    display: inline-flex;
237→    align-items: center;
238→    gap: 0.25rem;
239→    padding: 0.22rem 0.55rem;
240→    border-radius: 8px;
241→    background: linear-gradient(135deg, rgba(245, 158, 11, 0.12), rgba(212, 168, 83, 0.08));
242→    border: 1px solid rgba(245, 158, 11, 0.2);
243→    font-family: var(--font-ui);
244→    font-size: 0.62rem;
245→    font-weight: 700;
246→    color: var(--accent-amber);
247→    letter-spacing: 0.02rem;
248→}
249→.explore-hero-score-flame{
250→    width: 12px;
251→    height: 12px;
252→    color: var(--accent-amber);
253→}
254→
255→
256→/* ══════════════════════════════════════════
257→   RUNNER CARDS — #2-#5
258→   ══════════════════════════════════════════ */
259→
260→.explore-runners-section{
261→    padding: 0;
262→}
263→.explore-runners-section--search{
264→    padding: 0;
265→}
266→.explore-runners-list{
267→    display: flex;
268→    flex-direction: column;
269→    gap: 2px;
270→    padding: 0 8px;
271→    padding-bottom: 2rem;
272→}
273→
274→.explore-runner-card{
275→    display: flex;
276→    align-items: stretch;
277→    width: 100%;
278→    min-height: 0;
279→    background: var(--bg-card);
280→    border: 1px solid var(--border-card);
281→    border-radius: 12px;
282→    overflow: hidden;
283→    cursor: pointer;
284→    transition: box-shadow 0.25s ease, transform 0.25s ease, border-color 0.25s ease;
285→}
286→.explore-runner-card:hover{
287→    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
288→    transform: translateY(-1px);
289→    border-color: rgba(212, 168, 83, 0.2);
290→}
291→
292→/* Rank column */
293→.explore-runner-rank-col{
294→    display: flex;
295→    align-items: flex-start;
296→    justify-content: center;
297→    flex-shrink: 0;
298→    width: 38px;
299→    padding-top: 1rem;
300→}
301→.explore-runner-rank{
302→    font-family: "Lexend Deca", sans-serif;
303→    font-size: 1.15rem;
304→    font-weight: 800;
305→    line-height: 1;
306→    color: var(--border-card);
307→    user-select: none;
308→}
309→.explore-runner-rank--top{
310→    color: var(--accent-amber);
311→}
312→
313→/* Runner body */
314→.explore-runner-body{
315→    flex: 1;
316→    min-width: 0;
317→    display: flex;
318→    flex-direction: column;
319→    gap: 0.3rem;
320→    padding: 0.85rem 0.5rem 0.75rem 0;
321→}
322→.explore-runner-title{
323→    margin: 0;
324→    padding: 0;
325→    font-family: "Lexend Deca", sans-serif;
326→    font-size: 0.95rem;
327→    font-weight: 700;
328→    line-height: 1.35;
329→    letter-spacing: -0.02rem;
330→    color: var(--text-heading);
331→}
332→.explore-runner-excerpt{
333→    margin: 0;
334→    padding: 0;
335→    font-family: var(--font-serif);
336→    font-size: 0.8rem;
337→    font-weight: 400;
338→    line-height: 1.55;
339→    color: var(--text-body);
340→    display: -webkit-box;
341→    -webkit-line-clamp: 2;
342→    -webkit-box-orient: vertical;
343→    overflow: hidden;
344→}
345→.explore-runner-meta{
346→    display: flex;
347→    align-items: center;
348→    justify-content: space-between;
349→    flex-wrap: wrap;
350→    gap: 0.4rem;
351→    padding-top: 0.35rem;
352→}
353→.explore-runner-author{
354→    display: flex;
355→    align-items: center;
356→    gap: 0.35rem;
357→}
358→.explore-runner-stats{
359→    display: flex;
360→    align-items: center;
361→    gap: 0.3rem;
362→}
363→.explore-runner-flame-icon{
364→    width: 10px;
365→    height: 10px;
366→    color: var(--accent-amber);
367→    margin-right: 0.15rem;
368→}
369→
370→/* Runner thumbnail */
371→.explore-runner-thumb-wrap{
372→    flex-shrink: 0;
373→    width: 90px;
374→    display: flex;
375→    align-items: center;
376→    justify-content: center;
377→    overflow: hidden;
378→}
379→.explore-runner-thumb{
380→    width: 100%;
381→    height: 100%;
382→    object-fit: cover;
383→    transition: transform 0.3s ease;
384→}
385→.explore-runner-card:hover .explore-runner-thumb{
386→    transform: scale(1.04);
387→}
388→
389→
390→/* ── Score pill (shared) ── */
391→.explore-score-pill{
392→    display: inline-flex;
393→    align-items: center;
394→    justify-content: center;
395→    padding: 0.18rem 0.48rem;
396→    border-radius: 6px;
397→    border: 1px solid var(--border-card);
398→    background-color: var(--bg-pill);
399→    color: var(--text-faint);
400→    font-family: var(--font-ui);
401→    font-size: 0.58rem;
402→    font-weight: 650;
403→    line-height: 1;
404→    letter-spacing: 0.02rem;
405→    white-space: nowrap;
406→}
407→
408→/* ── Meta right (search mode) ── */
409→.explore-meta-right{
410→    display: flex;
411→    align-items: center;
412→    gap: 0.35rem;
413→    margin-left: auto;
414→}
415→
416→/* ── Explore rank (search mode) ── */
417→.explore-rank{
418→    display: flex;
419→    align-items: center;
420→    justify-content: center;
421→    width: 100%;
422→    padding: 0.15rem 1.15rem 0;
423→    box-sizing: border-box;
424→    font-family: "Lexend Deca", sans-serif;
425→    font-size: 1.15rem;
426→    font-weight: 800;
427→    line-height: 1;
428→    color: var(--border-card);
429→    user-select: none;
430→}
431→.explore-page-container .cards:nth-child(-n+3) .explore-rank{
432→    color: var(--accent-amber);
433→}
434→
435→/* ── Fix border stacking in search mode ── */
436→.explore-page-container .card-image-banner{
437→    border-bottom: none;
438→}
439→.explore-page-container .card-icons-container{
440→    border-top: none;
441→}
442→
443→/* ── Explore cards container (search mode fallback) ── */
444→.explore-postcards-parent-container{
445→    top: 0;
446→}
447→
